        if (profileError) {
          console.warn('[ADMIN-ADD] Profile upsert warning:', profileError.message);
        }
      }","newText":"      // Create new auth user if not found
      if (!user_id) {
        if (!email) {
          return badRequest(res, 'Email required to create a new member account. Phone-only creation not supported.');
        }

        const tempPassword = Math.random().toString(36).slice(-8) + Math.random().toString(36).slice(-4).toUpperCase() + '!1';

        const { data: authData, error: authError } = await supabaseAdmin.auth.admin.createUser({
          email: email.toLowerCase().trim(),
          email_confirm: true,
          user_metadata: { full_name, phone: phone || null },
          password: tempPassword,
        });

        if (authError || !authData.user) {
          return serverError(res, `Failed to create user account: ${authError?.message ?? 'Unknown error'}`);
        }

        user_id = authData.user.id;

        // Upsert the public.users profile directly ‚Äî don't rely on trigger timing.
        // The service role bypasses RLS so this always works regardless of trigger state.
        const { error: profileError } = await supabaseAdmin
          .from('users')
          .upsert({
            id: user_id,
            email: email.toLowerCase().trim(),
            full_name,
            phone: phone || null,
            role: 'member',
          }, { onConflict: 'id' });

        if (profileError) {
          // If upsert failed, the FK on gym_members will also fail ‚Äî surface the real error.
          console.error('[ADMIN-ADD] Profile upsert failed:', profileError);
          return serverError(res, `Failed to create user profile: ${profileError.message}`);
        }
      }"}]}

