        }

        user_id = authData.user.id;

        // Wait briefly for the auth trigger to fire and create the public.users row,
        // then upsert to ensure phone/full_name are correct regardless of trigger timing.
        await new Promise(r => setTimeout(r, 500));

        const { error: profileError } = await supabaseAdmin
