          // Don't hard-fail here ‚Äî the auth user exists, the trigger may have already created the row.
          // The FK on gym_members will catch any real issue.
        }
      }

      // Final safety check ‚Äî user_id must be set at this point
      if (!user_id) {
        return serverError(res, 'Could not resolve user account');
      }"}]}

